-- Add missing columns to users table
ALTER TABLE users ADD COLUMN IF NOT EXISTS profileType ENUM('customer', 'professional') NOT NULL DEFAULT 'customer';
ALTER TABLE users ADD COLUMN IF NOT EXISTS professionalFee DECIMAL(10,2) DEFAULT NULL;
ALTER TABLE users ADD COLUMN IF NOT EXISTS feeEnabled BOOLEAN NOT NULL DEFAULT false;

-- Add missing columns to categories table
ALTER TABLE categories ADD COLUMN IF NOT EXISTS nameAr VARCHAR(100) DEFAULT NULL;
ALTER TABLE categories ADD COLUMN IF NOT EXISTS descriptionAr TEXT DEFAULT NULL;
ALTER TABLE categories ADD COLUMN IF NOT EXISTS isBlocked BOOLEAN NOT NULL DEFAULT false;

-- Add missing columns to services table
ALTER TABLE services ADD COLUMN IF NOT EXISTS nameAr VARCHAR(100) DEFAULT NULL;
ALTER TABLE services ADD COLUMN IF NOT EXISTS descriptionAr TEXT DEFAULT NULL;
ALTER TABLE services ADD COLUMN IF NOT EXISTS isBlocked BOOLEAN NOT NULL DEFAULT false;

-- Add missing columns to professions table
ALTER TABLE professions ADD COLUMN IF NOT EXISTS serviceId INT NOT NULL DEFAULT 0;

-- Add missing columns to appointments table
ALTER TABLE appointments ADD COLUMN IF NOT EXISTS serviceId INT DEFAULT NULL;

-- Add missing columns to contact_messages table
ALTER TABLE contact_messages ADD COLUMN IF NOT EXISTS status ENUM('pending', 'in_progress', 'closed') NOT NULL DEFAULT 'pending';
ALTER TABLE contact_messages ADD COLUMN IF NOT EXISTS adminReply TEXT DEFAULT NULL;
ALTER TABLE contact_messages ADD COLUMN IF NOT EXISTS repliedAt TIMESTAMP DEFAULT NULL;

-- Create site_config table if not exists
CREATE TABLE IF NOT EXISTS site_config (
  id INT AUTO_INCREMENT PRIMARY KEY,
  configKey VARCHAR(100) NOT NULL UNIQUE,
  configValue TEXT DEFAULT NULL,
  updatedAt TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP
);

